import{bV as a,aL as o,u as l,G as t}from"./chunks/framework.BfzMay2U.js";const p=JSON.parse('{"title":"简述 Go 协程调度机制","description":"","frontmatter":{},"headers":[],"relativePath":"views/go/go-coroutine-dispath.md","filePath":"views/go/go-coroutine-dispath.md"}'),i={name:"views/go/go-coroutine-dispath.md"};function r(s,e,c,h,d,n){return o(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="简述-go-协程调度机制" tabindex="-1">简述 Go 协程调度机制 <a class="header-anchor" href="#简述-go-协程调度机制" aria-label="Permalink to &quot;简述 Go 协程调度机制&quot;">​</a></h1><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li class="todo"><input class="todo-checkbox" type="checkbox" checked disabled><a href="https://medium.com/@ankur_anand/illustrated-tales-of-go-runtime-scheduler-74809ef6d19b" target="_blank" rel="noreferrer">https://medium.com/@ankur_anand/illustrated-tales-of-go-runtime-scheduler-74809ef6d19b(需要科学上网)</a></li><li class="todo"><input class="todo-checkbox" type="checkbox" checked disabled><a href="https://lessisbetter.site/2019/03/10/golang-scheduler-1-history/" target="_blank" rel="noreferrer">https://lessisbetter.site/2019/03/10/golang-scheduler-1-history/(这个不错)</a></li><li class="todo"><input class="todo-checkbox" type="checkbox" checked disabled><a href="https://zhuanlan.zhihu.com/p/27056944" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/27056944(知乎的一篇文章)</a></li></ul><h2 id="真正干活的是线程-m" tabindex="-1">真正干活的是线程 M <a class="header-anchor" href="#真正干活的是线程-m" aria-label="Permalink to &quot;真正干活的是线程 M&quot;">​</a></h2><blockquote><p>OS 提供的线程：<code>M</code></p></blockquote><h2 id="协程" tabindex="-1">协程 <a class="header-anchor" href="#协程" aria-label="Permalink to &quot;协程&quot;">​</a></h2><p>是用户态的线程，是“用户”创建的，通常用<code>G</code>表示，协程自己不会运行，Go 有一个协程调度机制。</p><ul><li>G(goroutine)：代表携程</li><li>M（Work Thread）：代表线程</li><li>P(Processor)，代表处理器核(CPU 核)，又称上下文，不超过机器本身的<code>GOMAXPROCS</code></li></ul><ol><li>运行的 M 都必须绑定一个 P，一次只能绑定一个</li><li>P 保存着一个协程 G 的队列【本地队列】</li><li>调度器还拥有一个全局的 G 队列【全局队列】</li><li>M 从队列中提取 G，并执行</li></ol><h2 id="找-g-的顺序" tabindex="-1">找 G 的顺序 <a class="header-anchor" href="#找-g-的顺序" aria-label="Permalink to &quot;找 G 的顺序&quot;">​</a></h2><ol><li><p><code>1/61</code>的几率在全局队列中找 G，<code>60/61</code>的几率在本地队列找 G</p></li><li><p>如果全局队列找不到 G，就从 P 的本地队列里找 G</p></li><li><p>如果找不到，就从其他 P 的本地队列里“窃取”P</p></li><li><p>如果找不到，则从全局队列中拿取一部分 G 到本地队列，这里拿取的“一部分”满足一个公式： $$ n = min(len(GQ)/GOMAXPROCS + 1, len(GQ/2)) $$</p></li></ol><h2 id="阻塞过程" tabindex="-1">阻塞过程 <a class="header-anchor" href="#阻塞过程" aria-label="Permalink to &quot;阻塞过程&quot;">​</a></h2><blockquote><p>假设 G1 阻塞，从而造成 M1 阻塞</p></blockquote><ol><li>P1 第一件事就是和 M1 解绑</li><li>然后 M1 和 G1 依然保持关系</li><li>阻塞结束，M1 寻找 P【不一定是原来的 P1】来接收 G1，如果找不到，扔给全局队列</li></ol><h2 id="自旋" tabindex="-1">自旋 <a class="header-anchor" href="#自旋" aria-label="Permalink to &quot;自旋&quot;">​</a></h2><p>M 在本地队列、全局队列都找不到 G，则会进入自旋【有条件：如 2M &lt; 繁忙的 P，即当 M 的数量的 2 倍小于繁忙的 P 就会进入自旋】</p><blockquote><p>自旋：可以理解为循环执行某个代码块，从而不仅如此休眠，当然会耗费一些 CPU；</p><p><strong>但是比起反复启动新的 M 要性能高</strong></p></blockquote><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><blockquote><p>Go 的协程调度就是：P 将 G 合理的分配给某个 M 的过程。</p></blockquote>',19)])])}const b=a(i,[["render",r]]);export{p as __pageData,b as default};
